// Time:  O(n)
// Space: O(n)

// combinatorics, dp
class Solution {
public:
    long long countTheNumOfKFreeSubsets(vector<int>& nums, int k) {
        unordered_map<int, int> cnt;
        for (const auto& x : nums) {
            ++cnt[x];
        }
        const auto& count = [&](int x) {
            int y = x;
            for (; cnt.count(y - k); y -= k);
            vector<int64_t> dp = {1, 0};  // dp[0]: count without i, dp[1]: count with i
            for (int i = y; i <= x; i += k) {
                dp = {dp[0] + dp[1], dp[0] * ((1 << cnt[i]) - 1)};
            }
            return dp[0] + dp[1];
        };

        int64_t result = 1;
        for (const auto& [i, _] : cnt) {
            if (!cnt.count(i + k)) {
                result *= count(i);
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(n)

import collections
import operator


# combinatorics, dp
class Solution(object):
    def countTheNumOfKFreeSubsets(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        def count(x):
            y = x
            while y-k in cnt:
                y -= k
            dp = [1, 0]  # dp[0]: count without i, dp[1]: count with i
            for i in xrange(y, x+1, k):
                dp = [dp[0]+dp[1], dp[0]*((1<<cnt[i])-1)]
            return sum(dp)

        cnt = collections.Counter(nums)
        return reduce(operator.mul, (count(i) for i in cnt.iterkeys() if i+k not in cnt))
